c.customText:
function()
    local s = aura_env.state  
    local LWA = LWA and LWA["Druid"] or {}

    if LWA and LWA.UpdateBarText then
        local format = LWA.GetConfig("resources").health_bar.format

        return LWA.UpdateBarText(s.value, s.percenthealth, format)
    end

    return s.percenthealth 
end

function()
    local s = aura_env.state
    local LWA = LWA and LWA["Druid"] or {}

    if LWA and LWA.UpdateBarText then
        local format = LWA.GetConfig("resources").mana_bar.format

        return LWA.UpdateBarText(s.value, s.percentpower, format)
    end

    return s.percentpower 
end

